import React from 'react';
import { Users, Activity, Calendar, DollarSign } from "lucide-react";

const kpiData = [
  { title: "Check-ins de Hoy", value: "142", icon: Activity, change: "+12%" },
  { title: "Miembros Activos", value: "1,247", icon: Users, change: "+5.2%" },
  { title: "Clases Programadas", value: "18", icon: Calendar, change: "+2" },
  { title: "Ingresos del Mes", value: "€48,392", icon: DollarSign, change: "+18.7%" },
];

export function DashboardOverview() {
  return (
    <div className="space-y-6 text-white">
      <div>
        <h1 className="text-2xl font-bold text-white">Resumen del Dashboard</h1>
        <p className="text-gray-400 mt-1">¡Bienvenido de nuevo! Esto es lo que está pasando hoy.</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {kpiData.map((kpi) => {
          const Icon = kpi.icon;
          return (
            <div key={kpi.title} className="bg-[#1a1a1a] border border-[#2a2a2a] rounded-xl p-6">
              <div className="flex justify-between">
                <div>
                  <p className="text-gray-400 text-sm">{kpi.title}</p>
                  <p className="text-3xl font-bold mt-2">{kpi.value}</p>
                  <p className="text-[#39FF14] text-sm mt-2">{kpi.change}</p>
                </div>
                <div className="w-12 h-12 bg-[#39FF14]/10 rounded-lg flex items-center justify-center">
                  <Icon className="text-[#39FF14]" />
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
